61	pub fn find_child_by_field<'a>(
62	    node: tree_sitter::Node<'a>,
63	    field: &str,
64	) -> Option<tree_sitter::Node<'a>> {
65	    let mut cursor = node.walk();
66	    for child in node.children(&mut cursor) {
