// Mutation hardening tests — separate from unit and acceptance suites.
// Each test targets a specific surviving mutant identified by cargo-mutants.

use drywall::ast::{
    build_normalized_subtree, extract_functions, extract_let_declaration, make_parser,
};
use drywall::{FunctionInfo, find_duplicate_pairs, jaccard, source_lines};

fn parse_and_extract(source: &str) -> Vec<FunctionInfo> {
    let tree = make_parser().parse(source, None).unwrap();
    let mut functions = Vec::new();
    extract_functions(tree.root_node(), source, "test.rs", &mut functions);
    functions
}

fn make_fi(start_line: usize, end_line: usize, hashes: Vec<u64>) -> FunctionInfo {
    FunctionInfo {
        file: "test.rs".to_string(),
        start_line,
        end_line,
        node_hashes: hashes,
    }
}

// --- ast.rs:55 --- extract_let_declaration: child.kind() != "closure_expression"
// Mutant: replace != with ==
// Guard: when a let_declaration has a closure child, recursing INTO that closure must NOT happen,
// or we'd double-count. Verify the closure child is not recursively extracted as extra functions.
#[test]
fn let_decl_closure_child_not_recursed_into() {
    // A let with a multi-statement closure body. If we recurse into the closure_expression child,
    // we'd find no function_item inside, but the count must still be exactly 1 (the closure itself).
    let source = "let f = |x: i32| -> i32 { let y = x + 1; y * 2 };\n";
    let tree = make_parser().parse(source, None).unwrap();
    let mut functions = Vec::new();
    let root = tree.root_node();
    let mut cursor = root.walk();
    let children: Vec<_> = root.children(&mut cursor).collect();
    if let Some(let_node) = children.iter().find(|n| n.kind() == "let_declaration") {
        extract_let_declaration(*let_node, source, "test.rs", &mut functions);
    }
    // Exactly one: the outer closure. Not zero (which would happen if == replaced !=
    // and we never recursed non-closure children, but that's not the failure mode here).
    // The key: if != became == we would recurse INTO closure_expression children and skip
    // everything else — so nested function items inside non-closure let children would be missed.
    assert_eq!(functions.len(), 1, "expected exactly the closure, got {:?}", functions.len());
}

// Verify that non-closure let children ARE traversed (extract nested fn items from sub-nodes).
#[test]
fn let_decl_non_closure_children_are_traversed() {
    // A plain let that contains no closure; the extract_let_declaration should not add anything,
    // but it must not prevent traversal of other children.
    let source = "let x = 42;\n";
    let tree = make_parser().parse(source, None).unwrap();
    let mut functions = Vec::new();
    let root = tree.root_node();
    let mut cursor = root.walk();
    let children: Vec<_> = root.children(&mut cursor).collect();
    if let Some(let_node) = children.iter().find(|n| n.kind() == "let_declaration") {
        extract_let_declaration(*let_node, source, "test.rs", &mut functions);
    }
    assert_eq!(functions.len(), 0);
}

